import { AppClaw } from '../../src/sdk';
import { describe, it } from 'vitest';
import 'dotenv/config';

describe('Recorded flow', () => {
  it("tap first suggestion 'appium 3.0' with history icon", async () => {
    const app = new AppClaw({
      provider: 'gemini',
      apiKey: process.env.LLM_API_KEY,
      platform: 'android',
      agentMode: 'vision',
    });
    await app.run('open YouTube app');
    await app.run('tap magnifying-glass search icon in the top right corner');
    await app.run('type "appium 3.0" into search edit field with hint \'Search YouTube\' at top');
    await app.run("tap first suggestion 'appium 3.0' with history icon");

    await app.teardown();
  }, 120000);
});
